using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasData() now requires stable seed values.
        // DateTime.UtcNow is non-deterministic and causes a new migration on every run.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; }  }

// --- Cosmos DB Context demonstrating EF Core 9 breaking changes ---
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: EF Core 9 renamed the discriminator property from
        // "Discriminator" to "$type". For existing documents that use "Discriminator",
        // you must explicitly configure the old property name to avoid data mismatch.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>().ToContainer("Products");
    }

    // Breaking change #2: EF Core 9 removed synchronous Cosmos DB query support.
    // All queries must use async (ToListAsync, FirstOrDefaultAsync, etc.).
    // The sync methods (ToList, First, etc.) now throw InvalidOperationException.
    public async Task<List<Product>> GetProductsAsync()
        => await Products.ToListAsync();
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

